// Production-ready HMAC signature validation
const crypto = require('crypto');

// Get the raw body and signature from headers
const rawBody = JSON.stringify($input.first().json);
const receivedSignature = $input.first().json.headers['x-signature'];
const timestamp = $input.first().json.headers['x-timestamp'];

// Validate timestamp (prevent replay attacks)
const currentTime = Math.floor(Date.now() / 1000);
const requestTime = parseInt(timestamp);
const timeDiff = Math.abs(currentTime - requestTime);

if (timeDiff > 300) { // 5 minutes tolerance
  throw new Error('Request timestamp too old. Possible replay attack.');
}

// Create expected signature
const secret = 'your-webhook-secret-key'; // Should be from environment
const expectedSignature = crypto
  .createHmac('sha256', secret)
  .update(timestamp + rawBody)
  .digest('hex');

// Compare signatures
const isValid = crypto.timingSafeEqual(
  Buffer.from(receivedSignature, 'hex'),
  Buffer.from(expectedSignature, 'hex')
);

if (!isValid) {
  throw new Error('Invalid HMAC signature. Request rejected.');
}

// Log successful validation
console.log('✅ HMAC validation successful');

return {
  json: {
    ...$input.first().json,
    validation: {
      hmacValid: true,
      timestamp: requestTime,
      timeDiff: timeDiff
    }
  }
};

// Comprehensive payload validation
const payload = $input.first().json.body;

// Required fields validation
const requiredFields = ['event_type', 'data', 'timestamp', 'source'];
const missingFields = requiredFields.filter(field => !payload[field]);

if (missingFields.length > 0) {
  throw new Error(`Missing required fields: ${missingFields.join(', ')}`);
}

// Event type validation
const validEventTypes = ['user.created', 'user.updated', 'user.deleted', 'payment.completed', 'payment.failed'];
if (!validEventTypes.includes(payload.event_type)) {
  throw new Error(`Invalid event type: ${payload.event_type}`);
}

// Data structure validation
if (!payload.data || typeof payload.data !== 'object') {
  throw new Error('Data field must be an object');
}

// Email validation if present
if (payload.data.email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(payload.data.email)) {
    throw new Error('Invalid email format');
  }
}

// Log validation success
console.log('✅ Payload validation successful');

return {
  json: {
    ...$input.first().json,
    validation: {
      ...$input.first().json.validation,
      payloadValid: true,
      eventType: payload.event_type,
      dataIntegrity: true
    },
    payload: payload
  }
};

// Production-ready comprehensive logging
const logEntry = {
  timestamp: new Date().toISOString(),
  workflowId: 'webhook-security-validation',
  executionId: $execution.id,
  eventType: $input.first().json.payload.event_type,
  source: $input.first().json.payload.source,
  validation: $input.first().json.validation,
  payload: {
    size: JSON.stringify($input.first().json.payload).length,
    hasEmail: !!$input.first().json.payload.data?.email,
    hasUserId: !!$input.first().json.payload.data?.user_id
  },
  performance: {
    startTime: $execution.startedAt,
    currentTime: new Date().toISOString(),
    duration: Date.now() - new Date($execution.startedAt).getTime()
  },
  environment: 'production',
  version: '1.0.0'
};

// Log to console (in production, this would go to structured logging system)
console.log('📊 COMPREHENSIVE LOG ENTRY:', JSON.stringify(logEntry, null, 2));

// Store in execution data for database logging
return {
  json: {
    ...$input.first().json,
    logEntry: logEntry
  }
};

// Production-ready error handling with recovery strategies
const error = $input.first().json.error || $input.first().json;

// Categorize error type
let errorCategory = 'unknown';
let recoveryStrategy = 'none';
let retryable = false;

if (error.message?.includes('HMAC')) {
  errorCategory = 'authentication';
  recoveryStrategy = 'reject_request';
  retryable = false;
} else if (error.message?.includes('timestamp')) {
  errorCategory = 'replay_attack';
  recoveryStrategy = 'reject_request';
  retryable = false;
} else if (error.message?.includes('validation')) {
  errorCategory = 'data_validation';
  recoveryStrategy = 'return_error_response';
  retryable = false;
} else if (error.message?.includes('database')) {
  errorCategory = 'database_error';
  recoveryStrategy = 'retry_with_backoff';
  retryable = true;
} else if (error.message?.includes('timeout')) {
  errorCategory = 'timeout';
  recoveryStrategy = 'retry_with_backoff';
  retryable = true;
}

// Create error log entry
const errorLog = {
  timestamp: new Date().toISOString(),
  workflowId: 'webhook-security-validation',
  executionId: $execution.id,
  errorCategory: errorCategory,
  errorMessage: error.message,
  errorStack: error.stack,
  recoveryStrategy: recoveryStrategy,
  retryable: retryable,
  environment: 'production'
};

console.log('❌ ERROR HANDLED:', JSON.stringify(errorLog, null, 2));

return {
  json: {
    error: error,
    errorLog: errorLog,
    recoveryStrategy: recoveryStrategy,
    retryable: retryable
  }
};
